var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"운이 좋았어요. 적이 큰 부상을 입은 상태가 아니었다면 이렇게 쉽진 않았을 겁니다.","JPN":"運が良かったです。敵が手負いの状態でなければ、\\nこうもすんなりといかなかったと思います。","ENG":"We got lucky. It wouldn't have been this easy if the enemy wasn't already wounded so gravely.","TWN":"運氣不錯，要不是敵人受了重傷，我們應該無法贏得這麼輕鬆。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"저게 쉬운 편이었다고? 최전선이 어떻게 무너졌을지 짐작이 가네.","JPN":"あれですんなり行ったっていうの？　最前線の地獄ぶりが目に浮かぶようね。","ENG":"You call that easy? I'm starting to get a sense of how the front line fell.","TWN":"這叫輕鬆？我都能想像得到最前線是怎麼被擊潰的了。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L6_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"그나저나 어디서 이렇게 당했을까?","JPN":"それにしても、どうしてこんな深手を負っていたのかしら？","ENG":"Anyway, I wonder where it got those wounds?","TWN":"不過它是在哪裡受了這麼重的傷？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"꼭 무언가에 쫓겨 온 것 같던데.","JPN":"まるで何かから逃げてきたようだったわ。","ENG":"It seemed like something was chasing after it.","TWN":"好像是被什麼追趕到這裡的。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"지금은 궁금해 할 시간이 없습니다. 더 늦기 전에 빨리 이동하죠.","JPN":"今はそれを気にしている余裕はないんです。\\n急いで移動しましょう。","ENG":"There's no time for conjecture. We'd better get moving before it's too late.","TWN":"沒時間好奇了，趁現在快走吧！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"기다려.","JPN":"待って。","ENG":"Wait.","TWN":"等一下。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"류드밀라는 어떨지 몰라도, 난 설명을 들어야겠어.","JPN":"リュドミラちゃんはどうだか知らないけど、私は説明を要求するわ。","ENG":"Maybe Lyudmila was more accommodating, but I really need to hear an explanation.","TWN":"我和盧德米拉不一樣，我必須要聽到解釋。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"우리 애들 목숨이 걸린 일이야. 최소한 납득할 수 있는 이유를 들려 줘.","JPN":"うちの子どもたちの命がかかっているのよ。\\nせめて納得できる理由を聞かせてほしいの。","ENG":"My kids' lives are on the line. At least give me a reason I can accept.","TWN":"這事關我們孩子們的性命，至少給我一個能夠接受的理由。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"저도 모든 걸 알진 못합니다.","JPN":"僕もすべてがわかっているわけじゃないんです。","ENG":"I don't know everything either.","TWN":"我也不了解全部的事情。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"지금 말씀드릴 수 있는 건...... 이제 곧 세상이 끝난다는 겁니다.","JPN":"今お話できることは……間もなく世界が終わる、ということだけです。","ENG":"The only thing I can tell you is... that the world is about to end.","TWN":"不過我能告訴妳的是……這個世界即將就要毀滅。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"세상이 끝난다고? 그건 너무 부정적인 것 같은데?","JPN":"世界が終わるですって？\\nそれだけ絶望的ってことだろうけど、ちょっと大げさじゃないかしら。","ENG":"The world's going to end? That sounds a tad bit pessimistic, don't you think?","TWN":"世界毀滅？這也太悲觀了吧？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L19_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"쉽지 않은 싸움이 되겠지만, 잔존 병력을 모아서 다시 정비하면......","JPN":"厳しい戦いになるとは思うわ。\\nでも、残存兵力を集めてまた整備すれば……","ENG":"It won't be easy, but if we regroup whatever troops we've got left...","TWN":"雖然戰況艱難，但只要我們集結剩餘兵力，重整隊伍……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"제 말뜻을 이해하지 못하셨군요.","JPN":"話がまだ理解できていないようですね。","ENG":"I don't think you understand what I'm saying.","TWN":"看來妳沒有理解我的意思呢。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"제 말은 침식체가 더 많이 몰려온다거나, 싸울 사람이 부족하다거나...... 그런 뜻이 아니에요.","JPN":"僕が言ったのは侵食体がさらに押し寄せるとか、\\n戦闘要員が不足しているとか……そういう意味ではありません。","ENG":"I'm not saying more C.O.s are coming or we're short on troops... That's not what I'm talking about.","TWN":"我不是在說會有更多侵蝕體殺過來，戰鬥人員不足……這樣的意思。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"말 그대로, 세상이 종말을 맞이한다는 뜻입니다.","JPN":"言葉通り、世界が終焉を迎えるということなんです。","ENG":"I mean it quite literally. It's the end of the world.","TWN":"而是如字面上的意思，這個世界將迎來毀滅。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"뭐? 그럼 세상이 갑자기 없어지기라도 한다는 거야?","JPN":"えっ？　じゃあ何？　世界が急に消えて\\nなくなったりでもするというの？","ENG":"What? You mean the world's just going to disappear or something?","TWN":"什麼？也就是說這個世界會突然消失？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>프로토콜 CoW</color>란 일종의 철수작전입니다.","JPN":"<color=#ffd34c>プロトコルCoW</color>というのは、一種の撤退作戦です。","ENG":"<color=#ffd34c>Protocol: CoW</color> is a sort of a retreat plan.","TWN":"<color=#ffd34c>協議CoW</color>是一種撤退作戰。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_MAINSTREAM_003023","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};